    try {
      setFooter('Parsing ' + file.name + '...');
      const polys = await parseAreaFile(file);
      if (polys.length === 0) {
        setFooter('No polygons found in file');
        alert('No polygons found in the uploaded file.');
        return;
      }
      // Use the first polygon as the operational area (largest if multiple)
      let chosen = polys[0];
      let maxPts = chosen.length;
      for (const p of polys) {
        if (p.length > maxPts) { chosen = p; maxPts = p.length; }
      }
      const layer = L.polygon(chosen.map(pt => [pt.lat, pt.lng]), { color: '#dce6ef', weight: 2, fillOpacity: 0.05 });
      handleAreaCreated(layer);
      map.fitBounds(layer.getBounds(), { padding: [20, 20] });
      setFooter('Area loaded from ' + file.name);
    } catch (err) {
      console.error(err);
      alert('Failed to parse file: ' + err.message);
      setFooter('Parse failed');
    }
    e.target.value = ''; // allow re-uploading the same file
